var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"간호사 언니가 내일이면 눈에 감은 붕대를 풀 수 있대.","JPN":"看護師のお姉さんが明日には目に巻いた包帯を外せるって言ってた。","ENG":"The nurse said they'll take off the bandages from my eyes tomorrow.","TWN":"護士姐姐說，明天就能解開眼睛上的繃帶了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"이 일기장은 간호사 언니가 미리 글씨 연습을 하자고 준 거야.","JPN":"この日記帳は、看護師のお姉さんが文字を書く練習用にくれたの。","ENG":"She gave me this diary so I can practice writing afterwards.","TWN":"這本日記是護士姐姐為了讓我預先練習寫字給我的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하루에 있었던 일 중에 적고 싶은 일을 적으면 된대.","JPN":"一日の出来事の中で書きたいことを書けばいいんだって。","ENG":"She said I can write down whatever happened during the day.","TWN":"她說我可以把一天發生的事情中，想寫的事情寫在這本日記上。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 병원에서는 매일매일이 똑같아. 적고 싶은 일이 없어.","JPN":"だけど、病院の中じゃ毎日同じことばかり。書きたいことがない。","ENG":"But every day is the same at the hospital. There's nothing I want to write about here.","TWN":"但在醫院裡，每天的生活都一樣，沒有什麼想寫的事情。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까 내가 쓰고 싶은 얘기를 쓸래.","JPN":"だから私が書きたい話を書くね。","ENG":"So I'm just going to write whatever I want.","TWN":"所以我要把我想到的都寫上去。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"간호사 언니가 일기장은 보여 주고 싶은 사람에게만 보여 줘도 된다고 했으니까.","JPN":"看護師のお姉さんが、日記帳は見せたい人にだけ見せてもいいって言ってたから。","ENG":"The nurse said I don't have to show my diary to anyone except those I want.","TWN":"護士姐姐說可以只把日記拿給我想分享的人看。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 있던 창고에는 사람이 많았습니다.","JPN":"私がいた倉庫には大勢の人がいました。","ENG":"There were a lot of people in the warehouse I was in.","TWN":"我所在的倉庫裡有很多人。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"가끔씩 여러 명이 나가고, 여러 명이 들어왔어요.","JPN":"時々何人かの人が出ていって、また何人かが入ってきました。","ENG":"Sometimes several people would go out, and new people would come.","TWN":"偶爾會有很多人出去，很多人進來。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"처음 오는 사람들은 울기도 하고, 비명을 지르기도 하고......","JPN":"初めて来た人は泣いたり、悲鳴を上げたりするけれど……","ENG":"At first, they would cry or scream...","TWN":"第一次來的人有哭的，也有尖叫的……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"그러다가 몇 번 어른들에게 불려가면 아무 말도 없이 구석에 앉아 있게 됩니다.","JPN":"そのうち何回か大人たちに呼ばれると、何も言わずに隅っこでうずくまるようになります。","ENG":"But when the grown-ups take them away a few times, they learn to sit quietly in the corner.","TWN":"他們被大人們叫出去幾次，回來後就會縮在角落，一句話也不說。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 그러기 싫어서, 얌전히 지냈어요.","JPN":"私はそうなるのが嫌で、大人しく過ごしました。","ENG":"I stayed quiet because I didn't want that to happen to me.","TWN":"我不想變成那樣，所以一直都乖乖的。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"그날까지는요.","JPN":"あの日までは。","ENG":"Until that day, that is.","TWN":"直到那天。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"하아...... 하아...... 하아......","JPN":"はあ……はあ……はあ……","ENG":"*Huff*... *Huff*... *Huff*...","TWN":"哈啊……哈啊……哈啊……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"잡았다! 이 꼬맹이!","JPN":"捕まえたぞ！　この小娘！","ENG":"I got you! You little punk!","TWN":"抓到了！這小鬼！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"아......?!","JPN":"あ……！？","ENG":"Ah?!","TWN":"啊……？！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"휴우. 앞도 제대로 못 보는 꼬마가 무슨 생각으로 도망친 거야? 귀찮게시리.","JPN":"ふう。ちゃんと前も見えない小娘が何のつもりで逃げたんだ？　面倒くせぇな。","ENG":"Phew... What's a blind kid doing running away? It's such a hassle.","TWN":"呼。路都看不清的小鬼還想逃跑？真麻煩。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"놔......! 이거 놔아......!","JPN":"離して……！　離してよ……！","ENG":"Let go! Let go of me!","TWN":"放……！放開我……！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};